SELECT tr.trace_id, tr.drug_id, tr.batch_id, tr.document_type, tr.document_id, tr.operator_id, tr.operation_time, tr.quantity_change, tr.flow_node, d.drug_name, db.batch_no,
tr.audit_status, tr.auditor_id, tr.audit_time, tr.audit_remark, su2.login_name AS auditor_name FROM trace_record tr LEFT JOIN drug d ON tr.drug_id = d.drug_id LEFT JOIN drug_batch db ON tr.batch_id = db.batch_id LEFT JOIN sys_user su ON tr.operator_id = su.id LEFT JOIN sys_user su2 ON tr.auditor_id = su2.id WHERE 1=1
AND tr.drug_id = #{drugId}
AND tr.batch_id = #{batchId}
AND tr.document_type = #{documentType}
AND d.drug_name LIKE CONCAT('%', #{drugName}, '%')
AND db.batch_no LIKE CONCAT('%', #{batchNo}, '%')
AND su.login_name LIKE CONCAT('%', #{operatorName}, '%')
AND tr.flow_node LIKE CONCAT('%', #{flowNode}, '%')
AND tr.operation_time >= #{operationTimeStart}
AND tr.operation_time <= #{operationTimeEnd}
AND tr.audit_status = #{auditStatus}
ORDER BY tr.operation_time DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
FROM trace_record tr
LEFT JOIN drug d ON tr.drug_id = d.drug_id
LEFT JOIN drug_batch db ON tr.batch_id = db.batch_id
LEFT JOIN sys_user su ON tr.operator_id = su.id
LEFT JOIN sys_user su2 ON tr.auditor_id = su2.id 
WHERE 1=1

    AND tr.drug_id = #{drugId}


    AND tr.batch_id = #{batchId}


    AND tr.document_type = #{documentType}


    AND d.drug_name LIKE CONCAT('%', #{drugName}, '%')


    AND db.batch_no LIKE CONCAT('%', #{batchNo}, '%')


    AND su.login_name LIKE CONCAT('%', #{operatorName}, '%')


    AND tr.flow_node LIKE CONCAT('%', #{flowNode}, '%')


    AND tr.operation_time >= #{operationTimeStart}


    AND tr.operation_time <= #{operationTimeEnd}



    AND tr.audit_status = #{auditStatus}
